// src/utils/filename-sanitizer.ts
function sanitizeFilename(title) {
  if (!title || title.trim() === "") {
    return "untitled-note";
  }
  let sanitized = title.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^\p{L}\p{N}\s-]/gu, "").replace(/\s+/g, "-").trim().replace(/^\.+|-+\.+$/g, "").replace(/^\.*$/g, "untitled").replace(/^\/*$/g, "untitled").replace(/-+/g, "-");
  sanitized = sanitized.replace(/[-_.]+$/g, "");
  if (sanitized.length > 255) {
    sanitized = sanitized.substring(0, 252) + "...";
  }
  if (!sanitized || /^\s*$/.test(sanitized)) {
    sanitized = "untitled-note";
  }
  if (/^\d/.test(sanitized)) {
    sanitized = "note-" + sanitized;
  }
  sanitized = sanitized.replace(/[-_.]+$/g, "");
  return sanitized;
}

