// src/utils/error-utils.ts
function getSafeErrorMessage(error, defaultMessage = "Unknown error occurred") {
  try {
    return (error == null ? void 0 : error.message) || String(error) || defaultMessage;
  } catch (e) {
    return defaultMessage;
  }
}
function detectErrorCategory(error) {
  const message = getSafeErrorMessage(error);
  if (message.includes("network") || message.includes("fetch") || message.includes("connect") || message.includes("ECONNREFUSED") || message.includes("NetworkError") || message.includes("Failed to fetch")) {
    return "network" /* Network */;
  }
  if (message.includes("CORS") || message.includes("Cross-Origin") || message.includes("Access-Control-Allow-Origin")) {
    return "cors" /* CORS */;
  }
  if (message.includes("API key") || message.includes("authentication") || message.includes("auth") || message.includes("unauthorized")) {
    return "api_key" /* ApiKey */;
  }
  if (message.includes("rate limit") || message.includes("quota") || message.includes("too many requests")) {
    return "rate_limit" /* RateLimit */;
  }
  if (message.includes("context length") || message.includes("token limit") || message.includes("max_tokens")) {
    return "token_limit" /* TokenLimit */;
  }
  if (message.includes("timeout") || message.includes("timed out")) {
    return "timeout" /* Timeout */;
  }
  if (message.includes("not found") || message.includes("404")) {
    return "not_found" /* NotFound */;
  }
  return "unknown" /* Unknown */;
}
function createApiError(error, apiName) {
  const category = detectErrorCategory(error);
  const originalMessage = getSafeErrorMessage(error);
  switch (category) {
    case "network" /* Network */:
      return new Error(`[${apiName}] Network error while connecting to service. Please check your internet connection.`);
    case "cors" /* CORS */:
      return new Error(`[${apiName}] CORS policy blocked the request. Please check your connection or try a different request.`);
    case "api_key" /* ApiKey */:
      return new Error(`[${apiName}] Invalid API key or authentication error. Please check your settings.`);
    case "rate_limit" /* RateLimit */:
      return new Error(`[${apiName}] Rate limit reached or quota exceeded. Please try again later.`);
    case "token_limit" /* TokenLimit */:
      return new Error(`[${apiName}] Input too long for model's context window.`);
    case "timeout" /* Timeout */:
      return new Error(`[${apiName}] Request timed out. Please try again.`);
    case "not_found" /* NotFound */:
      return new Error(`[${apiName}] Resource not found. Please check the request parameters.`);
    default:
      return new Error(`[${apiName}] ${originalMessage}`);
  }
}
function handleApiError(error, apiName, context) {
  console.error(`[${apiName}]${context ? " [" + context + "]" : ""} Error:`, error);
  return createApiError(error, apiName);
}

